private fun importEmailConfigs(
    configs: List<EmailConfigExportDto>,
    providedSecrets: Map<String, String>,
    options: ImportOptions
): ImportEntityResult {
    var imported = 0
    var skipped = 0
    val errors = mutableListOf<String>()
    val warnings = mutableListOf<String>()

    configs.forEach { dto ->
        try {
            val existing = emailConfigRepository.findByName(dto.name)
            if (existing.isPresent) {
                if (options.skipExisting) {
                    skipped++
                    warnings.add("Email config '${dto.name}' already exists, skipping")
                } else {
                    errors.add("Email config '${dto.name}' already exists")
                }
            } else {
                // Resolve secrets from provided secrets map
                val smtpUsername = if (dto.hasSmtpUsername) {
                    providedSecrets["EmailConfig:${dto.name}:smtp_username"]
                } else null

                val smtpPassword = if (dto.hasSmtpPassword) {
                    providedSecrets["EmailConfig:${dto.name}:smtp_password"]
                } else null

                val sesAccessKey = if (dto.hasSesAccessKey) {
                    providedSecrets["EmailConfig:${dto.name}:ses_access_key"]
                } else null

                val sesSecretKey = if (dto.hasSesSecretKey) {
                    providedSecrets["EmailConfig:${dto.name}:ses_secret_key"]
                } else null

                // Warn if required secrets are missing but don't block import
                if (dto.hasSmtpPassword && smtpPassword.isNullOrBlank()) {
                    warnings.add("SMTP password not provided for email config '${dto.name}', credentials will need to be configured manually")
                }
                if (dto.hasSesAccessKey && sesAccessKey.isNullOrBlank()) {
                    warnings.add("SES access key not provided for email config '${dto.name}', credentials will need to be configured manually")
                }

                val config = com.secman.domain.EmailConfig(
                    name = dto.name,
                    provider = EmailProvider.valueOf(dto.provider),
                    smtpHost = dto.smtpHost,
                    smtpPort = dto.smtpPort,
                    smtpUsername = smtpUsername,
                    smtpPassword = smtpPassword,
                    smtpTls = dto.smtpTls,
                    smtpSsl = dto.smtpSsl,
                    fromEmail = dto.fromEmail,
                    fromName = dto.fromName,
                    imapHost = dto.imapHost,
                    imapPort = dto.imapPort,
                    imapEnabled = dto.imapEnabled,
                    sesAccessKey = sesAccessKey,
                    sesSecretKey = sesSecretKey,
                    sesRegion = dto.sesRegion,
                    isActive = false // Always import as inactive for safety
                )

                emailConfigRepository.save(config)
                imported++

                if (dto.isActive) {
                    warnings.add("Email config '${dto.name}' was active in source but imported as inactive for safety")
                }
            }
        } catch (e: Exception) {
            errors.add("Failed to import email config '${dto.name}': ${e.message}")
        }
    }

    return ImportEntityResult(imported, skipped, errors, warnings)
}

private fun importAwsAccountSharing(
    sharingRules: List<AwsAccountSharingExportDto>,
    options: ImportOptions
): ImportEntityResult {
    var imported = 0
    var skipped = 0
    val errors = mutableListOf<String>()
    val warnings = mutableListOf<String>()

    sharingRules.forEach { dto ->
        try {
            val sourceUser = userRepository.findByEmail(dto.sourceUserEmail)
            val targetUser = userRepository.findByEmail(dto.targetUserEmail)
            val createdByUser = userRepository.findByEmail(dto.createdByEmail)

            if (!sourceUser.isPresent) {
                errors.add("Source user '${dto.sourceUserEmail}' not found for AWS sharing rule")
                return@forEach
            }
            if (!targetUser.isPresent) {
                errors.add("Target user '${dto.targetUserEmail}' not found for AWS sharing rule")
                return@forEach
            }

            val source = sourceUser.get()
            val target = targetUser.get()
            val createdBy = createdByUser.orElse(source) // fallback to source user if creator not found

            if (!createdByUser.isPresent) {
                warnings.add("Created-by user '${dto.createdByEmail}' not found for AWS sharing rule ${dto.sourceUserEmail} -> ${dto.targetUserEmail}, using source user")
            }

            // Check if rule already exists
            if (awsAccountSharingRepository.existsBySourceUserIdAndTargetUserId(source.id!!, target.id!!)) {
                if (options.skipExisting) {
                    skipped++
                    warnings.add("AWS sharing rule ${dto.sourceUserEmail} -> ${dto.targetUserEmail} already exists, skipping")
                } else {
                    errors.add("AWS sharing rule ${dto.sourceUserEmail} -> ${dto.targetUserEmail} already exists")
                }
            } else {
                val sharing = AwsAccountSharing(
                    sourceUser = source,
                    targetUser = target,
                    createdBy = createdBy
                )
                awsAccountSharingRepository.save(sharing)
                imported++
            }
        } catch (e: Exception) {
            errors.add("Failed to import AWS sharing rule ${dto.sourceUserEmail} -> ${dto.targetUserEmail}: ${e.message}")
        }
    }

    return ImportEntityResult(imported, skipped, errors, warnings)
}

