                </>
              ) : (
                <>
                  <i className="bi bi-download me-2"></i>
                  Export Configuration
                </>
              )}
            </button>
          </div>
        )}

        {activeTab === 'import' && (
          <div>
            <h5 className="card-title">Import Configuration Bundle</h5>
            <p className="card-text text-muted">
