                  )}

                  {validationResult.errors.length > 0 && (
                    <div className="mb-3">
                      <h6>Errors:</h6>
                      <ul className="list-group">
                        {validationResult.errors.map((error, idx) => (
                          <li key={idx} className="list-group-item list-group-item-danger">{error}</li>
                        ))}
