  1→/**
  2→ * Vulnerability Exception Form Component
  3→ *
  4→ * Form for creating and editing vulnerability exceptions
  5→ *
  6→ * Features:
  7→ * - Exception type selection (IP/PRODUCT/ASSET)
  8→ * - Target value input with validation
  9→ * - Asset selector for ASSET exceptions
 10→ * - Product autocomplete for PRODUCT exceptions (Phase 3)
 11→ * - Expiration date picker (required)
 12→ * - Reason textarea
 13→ * - Form validation
 14→ *
 15→ * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 16→ * Related to: Feature 021-vulnerability-overdue-exception-logic (ASSET support, Phase 3 autocomplete)
 17→ */
 18→
 19→import React, { useState, useEffect } from 'react';
 20→import {
 21→    createException,
 22→    updateException,
 23→    getAssets,
 24→    previewExceptionImpact,
 25→    type VulnerabilityException,
 26→    type CreateExceptionRequest,
 27→    type UpdateExceptionRequest,
 28→    type Asset,
 29→    type ExceptionImpactPreview
 30→} from '../services/vulnerabilityManagementService';
 31→import ProductAutocomplete from './ProductAutocomplete';
 32→import ImpactPreviewModal from './ImpactPreviewModal';
 33→
 34→interface VulnerabilityExceptionFormProps {
 35→    exception?: VulnerabilityException;
 36→    onSave: () => void;
 37→    onCancel: () => void;
 38→}
 39→
 40→const VulnerabilityExceptionForm: React.FC<VulnerabilityExceptionFormProps> = ({
 41→    exception,
 42→    onSave,
 43→    onCancel
 44→}) => {
 45→    const [exceptionType, setExceptionType] = useState<string>(exception?.exceptionType || 'IP');
 46→    const [targetValue, setTargetValue] = useState<string>(exception?.targetValue || '');
 47→    const [selectedAssetId, setSelectedAssetId] = useState<number | null>(exception?.assetId || null);
 48→    const [cveScope, setCveScope] = useState<'all' | 'single'>('all');
 49→    const [expirationDate, setExpirationDate] = useState<string>(() => {
 50→        if (exception?.expirationDate) {
 51→            // Convert ISO string to datetime-local format
 52→            return exception.expirationDate.slice(0, 16);
 53→        }
 54→        // Default to 30 days from now
 55→        const future = new Date();
 56→        future.setDate(future.getDate() + 30);
 57→        return future.toISOString().slice(0, 16);
 58→    });
 59→    const [reason, setReason] = useState<string>(exception?.reason || '');
 60→    const [isSubmitting, setIsSubmitting] = useState(false);
 61→    const [error, setError] = useState<string | null>(null);
 62→    const [assets, setAssets] = useState<Asset[]>([]);
 63→    const [loadingAssets, setLoadingAssets] = useState(false);
 64→
 65→    // Phase 3: Impact preview state
 66→    const [showPreview, setShowPreview] = useState(false);
 67→    const [impactPreview, setImpactPreview] = useState<ExceptionImpactPreview | null>(null);
 68→    const [loadingPreview, setLoadingPreview] = useState(false);
 69→
 70→    const isEditMode = !!exception;
 71→
 72→    // Fetch assets when component mounts or when ASSET type is selected, or CVE with single scope
 73→    useEffect(() => {
 74→        if (exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) {
 75→            fetchAssets();
 76→        }
 77→    }, [exceptionType, cveScope]);
 78→
 79→    const fetchAssets = async () => {
 80→        try {
 81→            setLoadingAssets(true);
 82→            const data = await getAssets();
 83→            setAssets(data);
 84→        } catch (err) {
 85→            console.error('Failed to fetch assets:', err);
 86→            setError('Failed to load assets. Please try again.');
 87→        } finally {
 88→            setLoadingAssets(false);
 89→        }
 90→    };
 91→
 92→    const validateIPAddress = (ip: string): boolean => {
 93→        const ipPattern = /^(\d{1,3}\.){3}\d{1,3}$/;
 94→        if (!ipPattern.test(ip)) return false;
 95→
 96→        const parts = ip.split('.');
 97→        return parts.every(part => {
 98→            const num = parseInt(part, 10);
 99→            return num >= 0 && num <= 255;
100→        });
101→    };
102→
103→    const validateCveId = (cve: string): boolean => {
104→        return /^CVE-\d{4}-\d+$/i.test(cve);
105→    };
106→
107→    const parseCveIds = (input: string): string[] => {
108→        return input.split(',').map(s => s.trim()).filter(s => s.length > 0);
109→    };
110→
111→    const validateForm = (): boolean => {
112→        if (exceptionType === 'ASSET') {
113→            if (!selectedAssetId) {
114→                setError('Please select an asset');
115→                return false;
116→            }
117→            // For ASSET type, targetValue should be the asset name
118→            const selectedAsset = assets.find(a => a.id === selectedAssetId);
119→            if (!selectedAsset) {
120→                setError('Selected asset not found');
121→                return false;
122→            }
123→        } else if (exceptionType === 'CVE') {
124→            if (!targetValue.trim()) {
125→                setError('At least one CVE ID is required');
126→                return false;
127→            }
128→            const cveIds = parseCveIds(targetValue);
129→            if (cveIds.length === 0) {
130→                setError('At least one CVE ID is required');
131→                return false;
132→            }
133→            for (const cveId of cveIds) {
134→                if (!validateCveId(cveId)) {
135→                    setError(`Invalid CVE ID format: '${cveId}'. Expected format: CVE-YYYY-NNNNN`);
136→                    return false;
137→                }
138→            }
139→            if (targetValue.trim().length > 512) {
140→                setError('CVE list exceeds maximum length of 512 characters');
141→                return false;
142→            }
143→            if (cveScope === 'single' && !selectedAssetId) {
144→                setError('Please select an asset for single-system scope');
145→                return false;
146→            }
147→        } else {
148→            if (!targetValue.trim()) {
149→                setError('Target value is required');
150→                return false;
151→            }
152→
153→            if (exceptionType === 'IP' && !validateIPAddress(targetValue)) {
154→                setError('Invalid IP address format');
155→                return false;
156→            }
157→        }
158→
159→        if (!expirationDate) {
160→            setError('Expiration date is required');
161→            return false;
162→        }
163→
164→        if (!reason.trim()) {
165→            setError('Reason is required');
166→            return false;
167→        }
168→
169→        return true;
170→    };
171→
172→    // Phase 3: Handle preview impact
173→    const handlePreviewImpact = async () => {
174→        setError(null);
175→
176→        // Basic validation before preview
177→        if (exceptionType === 'ASSET' && !selectedAssetId) {
178→            setError('Please select an asset');
179→            return;
180→        }
181→        if (exceptionType === 'CVE' && !targetValue.trim()) {
182→            setError('CVE ID is required');
183→            return;
184→        }
185→        if (exceptionType !== 'ASSET' && exceptionType !== 'CVE' && !targetValue.trim()) {
186→            setError('Target value is required');
187→            return;
188→        }
189→
190→        setLoadingPreview(true);
191→
192→        try {
193→            let previewAssetId: number | null = null;
194→            if (exceptionType === 'ASSET') {
195→                previewAssetId = selectedAssetId;
196→            } else if (exceptionType === 'CVE' && cveScope === 'single') {
197→                previewAssetId = selectedAssetId;
198→            }
199→
200→            const preview = await previewExceptionImpact({
201→                exceptionType,
202→                targetValue: targetValue.trim(),
203→                assetId: previewAssetId
204→            });
205→
206→            setImpactPreview(preview);
207→            setShowPreview(true);
208→        } catch (err) {
209→            setError(err instanceof Error ? err.message : 'Failed to preview impact');
210→        } finally {
211→            setLoadingPreview(false);
212→        }
213→    };
214→
215→    // Phase 3: Create exception after preview confirmation
216→    const handleConfirmAndCreate = async () => {
217→        if (!validateForm()) {
218→            setShowPreview(false);
219→            return;
220→        }
221→
222→        setIsSubmitting(true);
223→
224→        try {
225→            // Create new exception
226→            let finalTargetValue = targetValue.trim();
227→            let finalAssetId = null;
228→
229→            if (exceptionType === 'ASSET') {
230→                const selectedAsset = assets.find(a => a.id === selectedAssetId);
231→                if (selectedAsset) {
232→                    finalTargetValue = selectedAsset.name;
233→                    finalAssetId = selectedAsset.id;
234→                }
235→            } else if (exceptionType === 'CVE') {
236→                if (cveScope === 'single' && selectedAssetId) {
237→                    finalAssetId = selectedAssetId;
238→                }
239→            }
240→
241→            const request: CreateExceptionRequest = {
242→                exceptionType,
243→                targetValue: finalTargetValue,
244→                expirationDate: new Date(expirationDate).toISOString(),
245→                reason: reason.trim(),
246→                assetId: finalAssetId
247→            };
248→            await createException(request);
249→
250→            setShowPreview(false);
251→            onSave();
252→        } catch (err) {
253→            setError(err instanceof Error ? err.message : 'Failed to save exception');
254→            setShowPreview(false);
255→        } finally {
256→            setIsSubmitting(false);
257→        }
258→    };
259→
260→    const handleSubmit = async (e: React.FormEvent) => {
261→        e.preventDefault();
262→        setError(null);
263→
264→        if (!validateForm()) {
265→            return;
266→        }
267→
268→        // Phase 3: For new exceptions, show preview first
269→        if (!isEditMode) {
270→            await handlePreviewImpact();
271→            return;
272→        }
273→
274→        // For edit mode, proceed directly
275→        setIsSubmitting(true);
276→
277→        try {
278→            // Update existing exception
279→            const request: UpdateExceptionRequest = {
280→                expirationDate: new Date(expirationDate).toISOString(),
281→                reason: reason.trim()
282→            };
283→            await updateException(exception.id, request);
284→
285→            onSave();
286→        } catch (err) {
287→            setError(err instanceof Error ? err.message : 'Failed to save exception');
288→        } finally {
289→            setIsSubmitting(false);
290→        }
291→    };
292→
293→    const handleTypeChange = (newType: string) => {
294→        setExceptionType(newType);
295→        setTargetValue('');
296→        setSelectedAssetId(null);
297→        setCveScope('all');
298→        setError(null);
299→    };
300→
301→
302→    return (
303→        <>
304→        <form onSubmit={handleSubmit}>
305→            {error && (
306→                <div className="alert alert-danger alert-dismissible fade show" role="alert">
307→                    <i className="bi bi-exclamation-triangle me-2"></i>
308→                    {error}
309→                    <button type="button" className="btn-close" onClick={() => setError(null)} aria-label="Close"></button>
310→                </div>
311→            )}
312→
313→            {/* Read-only context for edit mode */}
314→            {isEditMode && exception && (
315→                <div className="mb-4 p-3 bg-light rounded border">
316→                    <h6 className="text-muted mb-3">
317→                        <i className="bi bi-info-circle me-2"></i>
318→                        Exception Details
319→                    </h6>
320→                    <dl className="row mb-0">
321→                        <dt className="col-sm-3">Type</dt>
322→                        <dd className="col-sm-9">
323→                            <span className={`badge ${
324→                                exception.exceptionType === 'IP' ? 'bg-info' :
325→                                exception.exceptionType === 'PRODUCT' ? 'bg-warning text-dark' :
326→                                exception.exceptionType === 'CVE' ? 'bg-danger' :
327→                                'bg-secondary'
328→                            }`}>
329→                                {exception.exceptionType}
330→                            </span>
331→                        </dd>
332→
333→                        <dt className="col-sm-3">Target</dt>
334→                        <dd className="col-sm-9">
335→                            {exception.exceptionType === 'ASSET' && exception.assetName ? (
336→                                <>
337→                                    <i className="bi bi-server me-1"></i>
338→                                    <strong>{exception.assetName}</strong>
339→                                    <small className="text-muted ms-2">(ID: {exception.assetId})</small>
340→                                </>
