 941→                  {/* Pagination Controls */}
 942→                  {renderPagination()}
 943→                </>
 944→              )}
 945→            </div>
 946→          </div>
 947→        </div>
 948→      </div>
 949→
 950→      {/* Back to Home button */}
 951→      <div className="row mt-4">
 952→        <div className="col-12">
 953→          <a href="/" className="btn btn-secondary">
 954→            <i className="bi bi-house me-2"></i>
