 978→          style={{ backgroundColor: "rgba(0,0,0,0.5)" }}
 979→        >
 980→          <div className="modal-dialog modal-dialog-centered">
 981→            <div className="modal-content">
 982→              <div className="modal-header bg-success text-white">
 983→                <h5 className="modal-title">
 984→                  <i className="bi bi-check-circle me-2"></i>
 985→                  Cleanup Complete
 986→                </h5>
 987→                <button
 988→                  type="button"
 989→                  className="btn-close btn-close-white"
 990→                  onClick={handleCloseCleanupModal}
 991→                  aria-label="Close"
 992→                ></button>
 993→              </div>
 994→              <div className="modal-body">
 995→                <div className="alert alert-info mb-3">
 996→                  <i className="bi bi-info-circle me-2"></i>
 997→                  {cleanupResult.message}
 998→                </div>
 999→
1000→                <h6 className="mb-3">Statistics:</h6>
1001→                <table className="table table-sm">
1002→                  <tbody>
1003→                    <tr>
1004→                      <td>
1005→                        <strong>Total Scanned:</strong>
1006→                      </td>
1007→                      <td className="text-end">
1008→                        {cleanupResult.totalScanned.toLocaleString()}
1009→                      </td>
1010→                    </tr>
1011→                    <tr>
1012→                      <td>
1013→                        <strong>Duplicates Found:</strong>
1014→                      </td>
1015→                      <td className="text-end">
1016→                        <span
1017→                          className={
1018→                            cleanupResult.duplicatesFound > 0
1019→                              ? "text-warning"
1020→                              : "text-success"
1021→                          }
1022→                        >
1023→                          {cleanupResult.duplicatesFound.toLocaleString()}
1024→                        </span>
1025→                      </td>
1026→                    </tr>
