1028→                      <td>
1029→                        <strong>Duplicates Removed:</strong>
1030→                      </td>
1031→                      <td className="text-end">
1032→                        <span
1033→                          className={
1034→                            cleanupResult.duplicatesRemoved > 0
1035→                              ? "text-danger"
1036→                              : "text-muted"
1037→                          }
1038→                        >
1039→                          {cleanupResult.duplicatesRemoved.toLocaleString()}
1040→                        </span>
1041→                      </td>
1042→                    </tr>
1043→                    <tr className="table-active">
1044→                      <td>
1045→                        <strong>Unique Remaining:</strong>
1046→                      </td>
1047→                      <td className="text-end">
1048→                        <strong className="text-success">
1049→                          {cleanupResult.uniqueVulnerabilitiesRemaining.toLocaleString()}
1050→                        </strong>
