1055→
1056→                {cleanupResult.duplicatesRemoved > 0 && (
1057→                  <div className="alert alert-success mb-0 mt-3">
1058→                    <i className="bi bi-check2 me-2"></i>
1059→                    Successfully removed {cleanupResult.duplicatesRemoved}{" "}
1060→                    duplicate{cleanupResult.duplicatesRemoved !== 1 ? "s" : ""}!
1061→                  </div>
1062→                )}
1063→              </div>
1064→              <div className="modal-footer">
