401→                aVal = parseInt(a.daysOpen?.split(' ')[0] || '0');
402→                bVal = parseInt(b.daysOpen?.split(' ')[0] || '0');
403→            } else if (sortField === 'detectedAt') {
404→                aVal = new Date(a.detectedAt).getTime();
405→                bVal = new Date(b.detectedAt).getTime();
406→            } else {
407→                aVal = (a as any)[sortField];
408→                bVal = (b as any)[sortField];
409→            }
410→
411→            if (aVal === null || aVal === undefined) return 1;
412→            if (bVal === null || bVal === undefined) return -1;
413→
414→            const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
415→            return sortOrder === 'asc' ? comparison : -comparison;
416→        });
417→    };
418→
419→    /**
420→     * Handle sort
421→     * Task: T041 [US2-Impl]
422→     */
423→    const handleSort = (field: string) => {
424→        if (sortField === field) {
425→            setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
426→        } else {
427→            setSortField(field);
428→            setSortOrder('asc');
429→        }
430→    };
431→
432→    /**
433→     * Get severity badge class
434→     * Task: T035 [US1-Impl]
435→     */
436→    const getSeverityBadgeClass = (severity: string): string => {
437→        const sev = severity.toLowerCase();
438→        if (sev.includes('critical')) return 'bg-danger';
439→        if (sev.includes('high')) return 'bg-warning text-dark';
440→        if (sev.includes('medium')) return 'bg-info text-dark';
441→        if (sev.includes('low')) return 'bg-success';
442→        return 'bg-secondary';
443→    };
444→
445→    /**
446→     * Get exception badge
447→     * Task: T036 [US1-Impl]
448→     * Shows "N/A" when vulnerability is not yet overdue (< 30 days)
449→     */

