export interface CrowdStrikeVulnerabilityDto {
    id: string;
    hostname: string;
    ip: string | null;
    cveId: string | null;
    severity: string;
    cvssScore: number | null;
    affectedProduct: string | null;
    daysOpen: string | null;
    detectedAt: string;
    status: string;
